# test_flatten_dict.py
import pytest

from your_module import flatten_dict  # <-- change to the actual import path


def test_flatten_dict_happy_path_nested():
    d = {"a": {"b": 1, "c": 2}, "d": 3}
    assert flatten_dict(d) == {"a.b": 1, "a.c": 2, "d": 3}


def test_flatten_dict_happy_path_empty_dict():
    assert flatten_dict({}) == {}


def test_flatten_dict_single_level():
    d = {"a": 1, "b": 2}
    assert flatten_dict(d) == {"a": 1, "b": 2}


def test_flatten_dict_custom_separator():
    d = {"a": {"b": 1}}
    assert flatten_dict(d, sep="__") == {"a__b": 1}


def test_flatten_dict_with_parent_key_prefix():
    d = {"b": 1}
    assert flatten_dict(d, parent_key="a", sep=".") == {"a.b": 1}


def test_flatten_dict_works_when_values_are_none_and_empty_string():
    d = {"a": None, "b": ""}
    assert flatten_dict(d) == {"a": None, "b": ""}


def test_flatten_dict_edge_case_non_dict_subvalue_iterables_treated_as_leaf():
    # Lists/tuples are not dicts, so they should be treated as values (leaf)
    d = {"a": [1, 2], "b": (3, 4)}
    assert flatten_dict(d) == {"a": [1, 2], "b": (3, 4)}


def test_flatten_dict_edge_case_non_string_keys():
    # f-string will stringify keys; behavior should be consistent
    d = {1: {"x": 2}}
    assert flatten_dict(d) == {"1.x": 2}


def test_flatten_dict_error_when_d_is_not_dict():
    with pytest.raises(AttributeError):
        # .items() doesn't exist for non-dicts; function will fail when iterating
        flatten_dict(None)


def test_flatten_dict_error_when_d_items_not_iterable():
    class BadDict:
        def items(self):
            raise TypeError("boom")

    with pytest.raises(TypeError):
        flatten_dict(BadDict())


def test_flatten_dict_error_when_parent_key_not_str():
    d = {"a": 1}
    # parent_key used in f-string concatenation; non-str parent_key triggers TypeError
    with pytest.raises(TypeError):
        flatten_dict(d, parent_key=123)  # f'{parent_key}{sep}{k}' fails


def test_flatten_dict_error_when_sep_not_str():
    d = {"a": 1, "b": {"c": 2}}
    # sep used in f-string concatenation; if sep isn't str, concatenation fails
    with pytest.raises(TypeError):
        flatten_dict(d, sep=None)


def test_flatten_dict_error_when_nested_value_is_dict_like_but_not_dict():
    # Only actual dict instances are flattened; other mapping types are treated as leaf
    class MappingLike:
        def items(self):
            return [("x", 1)]

    # Should not flatten because it isn't an instance of dict
    d = {"a": MappingLike()}
    assert flatten_dict(d) == {"a": d["a"]}  # leaf retained
